// DaemonServiceServer is the server API for DaemonService service.
// All implementations must embed UnimplementedDaemonServiceServer
// for forward compatibility.
//
// DaemonService defines the gRPC API for CLI <-> Daemon communication
// Communication occurs over Unix domain socket for security and performance
type DaemonServiceServer interface {
	// NavigateShip initiates a ship navigation operation as a background container
	NavigateShip(context.Context, *NavigateShipRequest) (*NavigateShipResponse, error)
	// RouteShip initiates a cross-system point-to-point travel operation as a
	// background container (sp-6hjw). Unlike NavigateShip (in-system only), it reuses
	// the multi-jump travel machinery so a hull can reach a waypoint in any system.
	RouteShip(context.Context, *RouteShipRequest) (*RouteShipResponse, error)
	// DockShip docks a ship at its current location
	DockShip(context.Context, *DockShipRequest) (*DockShipResponse, error)
	// OrbitShip puts a ship into orbit from docked position
	OrbitShip(context.Context, *OrbitShipRequest) (*OrbitShipResponse, error)
	// RefuelShip refuels a ship at its current location
	RefuelShip(context.Context, *RefuelShipRequest) (*RefuelShipResponse, error)
	// JumpShip executes a jump to a different star system via jump gate
	JumpShip(context.Context, *JumpShipRequest) (*JumpShipResponse, error)
	// InstallModule installs a module (e.g. MODULE_CARGO_HOLD_III) from the ship's
	// cargo onto the ship. Single-writer daemon op (RULING #3): atomically claims
	// the hull, verifies the module is in cargo, gates the modification fee on the
	// working-capital floor (RULING #4), docks, installs, and persists the ship's
	// new cargo capacity. Synchronous — returns the post-install capacity + fee.
	InstallModule(context.Context, *InstallModuleRequest) (*InstallModuleResponse, error)
	// RemoveModule removes an installed module from the ship back into its cargo.
	// Mirror image of InstallModule (same claim/fee/persist guarantees).
	RemoveModule(context.Context, *RemoveModuleRequest) (*RemoveModuleResponse, error)
	// ListShipModules lists the modules currently installed on a ship (read-only,
	// no claim).
	ListShipModules(context.Context, *ListShipModulesRequest) (*ListShipModulesResponse, error)
	// BatchContractWorkflow executes batch contract workflow operations
	BatchContractWorkflow(context.Context, *BatchContractWorkflowRequest) (*BatchContractWorkflowResponse, error)
	// ContractFleetCoordinator manages a pool of ships for continuous contract execution
	ContractFleetCoordinator(context.Context, *ContractFleetCoordinatorRequest) (*ContractFleetCoordinatorResponse, error)
	// ScoutTour executes market scouting tour operations (single ship)
	ScoutTour(context.Context, *ScoutTourRequest) (*ScoutTourResponse, error)
	// ScoutMarkets orchestrates fleet deployment for market scouting (multi-ship with VRP)
	ScoutMarkets(context.Context, *ScoutMarketsRequest) (*ScoutMarketsResponse, error)
	// AssignScoutingFleet auto-discovers probe/satellite ships and assigns them to scout markets
	AssignScoutingFleet(context.Context, *AssignScoutingFleetRequest) (*AssignScoutingFleetResponse, error)
	// ScoutPostCoordinator starts the standing scout-post coordinator (sp-cxpq)
	ScoutPostCoordinator(context.Context, *ScoutPostCoordinatorRequest) (*ScoutPostCoordinatorResponse, error)
	// TradeFleetCoordinator starts the standing trade-fleet coordinator (sp-1278):
	// keeps continuous tours alive on 'trade'-dedicated hulls, relaunching on honest
	// exit after a cooldown. Retires the captain hand-relaunch loop.
	TradeFleetCoordinator(context.Context, *TradeFleetCoordinatorRequest) (*TradeFleetCoordinatorResponse, error)
	// SitingCoordinator starts the standing factory-siting coordinator (sp-vdld): the
	// "brain" that automates factory discovery/placement/capacity — each slow tick it
	// scans candidate sites, scores them by branchPL, maintains the top-K portfolio,
	// launches/retires goods_factory chains through the guard stack, and emits scout-demand.
	SitingCoordinator(context.Context, *SitingCoordinatorRequest) (*SitingCoordinatorResponse, error)
	// FleetAutosizerCoordinator starts the standing fleet capacity autosizer (sp-1txd): sizes
	// the hull pool to demand and auto-buys hulls (lights to factory demand, heavies to trade
	// demand) behind the full fail-closed money-guard stack. LIVE BY DEFAULT once launched.
	FleetAutosizerCoordinator(context.Context, *FleetAutosizerCoordinatorRequest) (*FleetAutosizerCoordinatorResponse, error)
	// BootstrapCoordinator starts the standing captain bootstrap coordinator (sp-3nbe): a
	// reconciler that drives a cold agent through the cold-start arc to the jump gate. Slice 1
	// ships the DATA phase (probes → 3, scout every market). LIVE BY DEFAULT once launched.
	BootstrapCoordinator(context.Context, *BootstrapCoordinatorRequest) (*BootstrapCoordinatorResponse, error)
	// FrontierExpansionCoordinator starts the standing frontier expansion coordinator (sp-8w89)
	FrontierExpansionCoordinator(context.Context, *FrontierExpansionCoordinatorRequest) (*FrontierExpansionCoordinatorResponse, error)
	// WorkerRebalancerCoordinator starts the standing worker-rebalancer coordinator (sp-f5pr):
	// ferries idle light-haulers cross-system to worker-starved factory systems. All tuning
	// lives in config.yaml [worker_rebalancer]; this request names the player/agent + dry_run.
	WorkerRebalancerCoordinator(context.Context, *WorkerRebalancerCoordinatorRequest) (*WorkerRebalancerCoordinatorResponse, error)
	// AddScoutPost adds or updates a desired-state scout post for a system
	AddScoutPost(context.Context, *AddScoutPostRequest) (*ScoutPostResponse, error)
	// RemoveScoutPost removes a scout post for a system
	RemoveScoutPost(context.Context, *RemoveScoutPostRequest) (*RemoveScoutPostResponse, error)
	// ListScoutPosts returns the active scout posts for a player
	ListScoutPosts(context.Context, *ListScoutPostsRequest) (*ListScoutPostsResponse, error)
	// ListContainers returns all running background containers
	ListContainers(context.Context, *ListContainersRequest) (*ListContainersResponse, error)
	// GetContainer returns detailed information about a specific container
	GetContainer(context.Context, *GetContainerRequest) (*GetContainerResponse, error)
	// StopContainer stops a running background container
	StopContainer(context.Context, *StopContainerRequest) (*StopContainerResponse, error)
	// GetContainerLogs retrieves logs from a container
	GetContainerLogs(context.Context, *GetContainerLogsRequest) (*GetContainerLogsResponse, error)
	// HealthCheck verifies daemon is running and responsive
	HealthCheck(context.Context, *HealthCheckRequest) (*HealthCheckResponse, error)
	// GetAPIBudget returns API request-budget observability (sp-51ti):
	// per-hull req/s, global utilization vs the rate ceiling (429 rate, poll
	// cadence share of the budget, headroom), and the duty-cycle KPI
	// (ship-hours earning/day per hull).
	GetAPIBudget(context.Context, *GetAPIBudgetRequest) (*GetAPIBudgetResponse, error)
	// ListShips returns all ships for a player
	ListShips(context.Context, *ListShipsRequest) (*ListShipsResponse, error)
	// GetShip returns detailed information about a specific ship
	GetShip(context.Context, *GetShipRequest) (*GetShipResponse, error)
	// RefreshShip forces a resync of a ship from the API, overwriting the cache
	RefreshShip(context.Context, *RefreshShipRequest) (*RefreshShipResponse, error)
	// ReserveShip reserves a ship for the captain's direct manual use, hiding
	// it from every coordinator's assignment discovery (sp-i1ku)
	ReserveShip(context.Context, *ReserveShipRequest) (*ReserveShipResponse, error)
	// ReleaseShip clears a captain reservation, returning the ship to idle so
	// normal coordinator discovery can claim it again (sp-i1ku)
	ReleaseShip(context.Context, *ReleaseShipRequest) (*ReleaseShipResponse, error)
	// AssignShipFleet dedicates a ship to a named fleet, making it exclusive
	// to that fleet's coordinator (sp-l7h2)
	AssignShipFleet(context.Context, *AssignShipFleetRequest) (*AssignShipFleetResponse, error)
	// UnassignShipFleet clears a ship's fleet dedication, returning it to the
	// general pool (sp-l7h2)
	UnassignShipFleet(context.Context, *UnassignShipFleetRequest) (*UnassignShipFleetResponse, error)
	// ListFleets lists every dedicated fleet and its member ships (sp-l7h2)
	ListFleets(context.Context, *ListFleetsRequest) (*ListFleetsResponse, error)
	// FleetHub adds or removes a standby-station ("hub") waypoint on a RUNNING
	// operation's coordinator, live, with no container restart (sp-jcke). The
	// coordinator reads its standby set from its own container config every
	// discovery pass, so a hub added draws idle dedicated hulls toward it and a
	// hub removed re-homes its hulls to the remaining set on the next tick. The
	// daemon is the sole writer of the persisted set (RULINGS #3).
	FleetHub(context.Context, *FleetHubRequest) (*FleetHubResponse, error)
	// ListWaypoints lists the waypoints of a system from the daemon's waypoint cache
	ListWaypoints(context.Context, *ListWaypointsRequest) (*ListWaypointsResponse, error)
	// GetWaypoint returns the detail of a single waypoint
	GetWaypoint(context.Context, *GetWaypointRequest) (*GetWaypointResponse, error)
	// PurchaseShip purchases a single ship from a shipyard
	PurchaseShip(context.Context, *PurchaseShipRequest) (*PurchaseShipResponse, error)
	// BatchPurchaseShips purchases multiple ships from a shipyard as a background operation
	BatchPurchaseShips(context.Context, *BatchPurchaseShipsRequest) (*BatchPurchaseShipsResponse, error)
	// GetShipyardListings retrieves available ships at a shipyard
	GetShipyardListings(context.Context, *GetShipyardListingsRequest) (*GetShipyardListingsResponse, error)
	// StartGoodsFactory initiates automated goods production using supply chain fabrication
	StartGoodsFactory(context.Context, *StartGoodsFactoryRequest) (*StartGoodsFactoryResponse, error)
	// StopGoodsFactory stops a running goods factory operation
	StopGoodsFactory(context.Context, *StopGoodsFactoryRequest) (*StopGoodsFactoryResponse, error)
	// FactoryWorkerCap sets the live concurrent-hull cap on a RUNNING goods factory
	// operation (sp-ev0n). The coordinator re-reads it each production pass and
	// converges its fan-out to N with no container restart; the cap persists across
	// restarts.
	FactoryWorkerCap(context.Context, *FactoryWorkerCapRequest) (*FactoryWorkerCapResponse, error)
	// GetFactoryStatus retrieves status and progress of a goods factory
	GetFactoryStatus(context.Context, *GetFactoryStatusRequest) (*GetFactoryStatusResponse, error)
	// ScanArbitrageOpportunities scans markets for profitable arbitrage opportunities
	ScanArbitrageOpportunities(context.Context, *ScanArbitrageOpportunitiesRequest) (*ScanArbitrageOpportunitiesResponse, error)
	// StartArbitrageCoordinator initiates automated arbitrage trading operations
	StartArbitrageCoordinator(context.Context, *StartArbitrageCoordinatorRequest) (*StartArbitrageCoordinatorResponse, error)
	// JettisonCargo jettisons cargo from a ship
	JettisonCargo(context.Context, *JettisonCargoRequest) (*JettisonCargoResponse, error)
	// GasExtractionOperation starts a gas extraction operation with siphon and transport ships
	GasExtractionOperation(context.Context, *GasExtractionOperationRequest) (*GasExtractionOperationResponse, error)
	// StartTradeRoute launches a single-hull pure-arbitrage circuit as a recovery-safe daemon container
	StartTradeRoute(context.Context, *StartTradeRouteRequest) (*StartTradeRouteResponse, error)
	// StartWarehouse launches a passive inventory warehouse (sp-dchv Lane B) on a dedicated
	// storage hull parked at a home waypoint, as a recovery-safe daemon container.
	StartWarehouse(context.Context, *StartWarehouseRequest) (*StartWarehouseResponse, error)
	// StartArbRun launches a ONE-SHOT, captain-directed, guarded arbitrage run (sp-p4ua):
	// buy a named good at a source waypoint, route (cross-gate) to a destination, sell once, stop.
	StartArbRun(context.Context, *StartArbRunRequest) (*StartArbRunResponse, error)
	// StartTourRun launches a ONE-SHOT, captain-directed, guarded multi-hop trade tour
	// (sp-1ek0): plan a depth-aware tour for one idle hull, fly it leg by leg with prices
	// re-verified live, re-plan on drift, and stop.
	StartTourRun(context.Context, *StartTourRunRequest) (*StartTourRunResponse, error)
	// StartStocker launches the STOCKER LOOP (sp-zdwg): a dedicated hull that fills a home
	// warehouse the tours rationally won't (sp-dchv). Each round-trip it need-ranks the
	// most-needed stock good, buys it at the cheapest foreign market (live-verified,
	// fail-closed), hauls home, and deposits — until nothing is left to stock.
	StartStocker(context.Context, *StartStockerRequest) (*StartStockerResponse, error)
	// StartConstructionPipeline starts a pipeline to supply materials to a construction site
	StartConstructionPipeline(context.Context, *StartConstructionPipelineRequest) (*StartConstructionPipelineResponse, error)
	// GetConstructionStatus retrieves the status of a construction site
	GetConstructionStatus(context.Context, *GetConstructionStatusRequest) (*GetConstructionStatusResponse, error)
	// StopConstructionPipeline cancels the active construction pipeline for a site (sp-yzrv)
	StopConstructionPipeline(context.Context, *StopConstructionPipelineRequest) (*StopConstructionPipelineResponse, error)
	// ConstructionGoodOverride sets or clears one good's per-good buy-gating override (the sp-sdyo
	// override map) on a RUNNING construction pipeline live, with no restart (sp-pdb3). The
	// coordinator / task activator re-read the persisted overrides on their next discovery pass.
	ConstructionGoodOverride(context.Context, *ConstructionGoodOverrideRequest) (*ConstructionGoodOverrideResponse, error)
	// --- Contract depot management (sp-u9xa) ---
	// The daemon is the single writer of contract-depot topology; every mutation is durable
	// the instant it returns (through the application Store into the DB), so a granular edit
	// needs no restart to take effect. ApplyDepotTopology is the declarative bulk apply; the
	// rest are granular live ops.
	ApplyDepotTopology(context.Context, *ApplyDepotTopologyRequest) (*ApplyDepotTopologyResponse, error)
	AddDepot(context.Context, *AddDepotRequest) (*AddDepotResponse, error)
	RemoveDepot(context.Context, *RemoveDepotRequest) (*RemoveDepotResponse, error)
	AddDepotElement(context.Context, *AddDepotElementRequest) (*DepotElementResponse, error)
	RemoveDepotElement(context.Context, *RemoveDepotElementRequest) (*DepotElementResponse, error)
	PlaceDepotElement(context.Context, *PlaceDepotElementRequest) (*DepotElementResponse, error)
	ListDepots(context.Context, *ListDepotsRequest) (*ListDepotsResponse, error)
	// Lifecycle (sp-38xc): StartDepot persists ONE depot's topology AND launches its
	// coordinators in one shot (live activation, no restart; idle-idempotent so a re-run
	// never double-launches). StopDepot tears down that depot's running coordinators.
	StartDepot(context.Context, *StartDepotRequest) (*StartDepotResponse, error)
	StopDepot(context.Context, *StopDepotRequest) (*StopDepotResponse, error)
	mustEmbedUnimplementedDaemonServiceServer()
}

